# Integrating Claude into Next.js with Streaming

Here's the simplest approach using the Anthropic SDK:

## 1. Install Dependencies

```bash
npm install @anthropic-ai/sdk
```

## 2. Create an API Route

Create `app/api/chat/route.ts`:

```typescript
import Anthropic from "@anthropic-ai/sdk";
import { NextRequest } from "next/server";

const client = new Anthropic();

export async function POST(request: NextRequest) {
  const { messages } = await request.json();

  const stream = await client.messages.stream({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    system:
      "You are a helpful assistant analyzing user data. Answer questions clearly and concisely.",
    messages,
  });

  return stream.toResponse();
}
```

## 3. Create a Client Component

Create `components/ChatInterface.tsx`:

```typescript
"use client";

import { useState, useRef, useEffect } from "react";

interface Message {
  role: "user" | "assistant";
  content: string;
}

export default function ChatInterface() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage = input;
    setInput("");
    setMessages((prev) => [...prev, { role: "user", content: userMessage }]);
    setLoading(true);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          messages: [...messages, { role: "user", content: userMessage }],
        }),
      });

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let assistantMessage = "";

      if (reader) {
        setMessages((prev) => [
          ...prev,
          { role: "assistant", content: "" },
        ]);

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value);
          const lines = chunk.split("\n");

          for (const line of lines) {
            if (line.startsWith("data: ")) {
              try {
                const data = JSON.parse(line.slice(6));
                if (
                  data.type === "content_block_delta" &&
                  data.delta.type === "text_delta"
                ) {
                  assistantMessage += data.delta.text;
                  setMessages((prev) => {
                    const updated = [...prev];
                    updated[updated.length - 1].content = assistantMessage;
                    return updated;
                  });
                }
              } catch {
                // Skip parsing errors
              }
            }
          }
        }
      }
    } catch (error) {
      console.error("Error:", error);
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "Sorry, there was an error processing your request.",
        },
      ]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-2xl mx-auto p-4">
      <div className="flex-1 overflow-y-auto mb-4 space-y-4">
        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`p-3 rounded-lg ${
              msg.role === "user"
                ? "bg-blue-500 text-white ml-auto max-w-xs"
                : "bg-gray-200 text-black mr-auto max-w-xs"
            }`}
          >
            {msg.content}
          </div>
        ))}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSubmit} className="flex gap-2">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          disabled={loading}
          placeholder="Ask a question..."
          className="flex-1 p-2 border rounded-lg"
        />
        <button
          type="submit"
          disabled={loading}
          className="px-4 py-2 bg-blue-500 text-white rounded-lg disabled:bg-gray-400"
        >
          {loading ? "..." : "Send"}
        </button>
      </form>
    </div>
  );
}
```

## 4. Set Environment Variable

Add to `.env.local`:

```
ANTHROPIC_API_KEY=your_api_key_here
```

## 5. Use in Your App

```typescript
import ChatInterface from "@/components/ChatInterface";

export default function Home() {
  return <ChatInterface />;
}
```

## Key Features

✅ **Real-time streaming** – Text appears as it's generated  
✅ **Conversation history** – Context preserved across messages  
✅ **Simple setup** – No complex SDKs or frameworks needed  
✅ **Error handling** – Graceful fallbacks  

